  const [depot] = await db.insert(depots).values({
    code: `I${TEST_SUFFIX}`,
    name: `Test Depot ${TEST_SUFFIX}`,
    timezone: 'UTC',
  }).returning();
  testDepotId = depot.id;

  // Create test fleet with unique code (max 10 chars)
  const [fleet] = await db.insert(fleets).values({
    code: `F${TEST_SUFFIX}`,
    name: `Test Fleet ${TEST_SUFFIX}`,
    manufacturer: 'Test Manufacturer',
    carsPerTrain: 4,
    baseDepotId: testDepotId,
  }).returning();
  testFleetId = fleet.id;

  // Create test trains with unique numbers
  for (let i = 1; i <= 3; i++) {
    const [train] = await db.insert(trains).values({
      trainNumber: `${TEST_SUFFIX}-${i}`,
      fleetId: testFleetId,
      currentMileageKm: 100000 + (i * 10000),
      fitnessStatus: 'FIT',
      currentDepotId: testDepotId,
      homeDepotId: testDepotId,
    }).returning();
    testTrainIds.push(train.id);
  }
}

// Clean up test data
async function cleanupTestData(): Promise<void> {
  if (!databaseAvailable) return;

  // Delete in reverse order of dependencies
  if (testTrainIds.length > 0) {
    // Use proper Drizzle inArray instead of raw SQL with ANY
    await db.delete(mileageReadings).where(inArray(mileageReadings.trainId, testTrainIds));
    await db.delete(meterEvents).where(inArray(meterEvents.trainId, testTrainIds));
    await db.delete(trains).where(inArray(trains.id, testTrainIds));
  }

  if (testFleetId) {
    await db.delete(fleets).where(eq(fleets.id, testFleetId));
  }

  if (testDepotId) {
    await db.delete(depots).where(eq(depots.id, testDepotId));
  }

  testTrainIds = [];
}

